package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;

class CSVFormatTest {

    @Test
    void testIsLineBreak_withLF() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);
        boolean result = (boolean) method.invoke(null, '\n'); // LF
        assertTrue(result);
    }

    @Test
    void testIsLineBreak_withCR() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);
        boolean result = (boolean) method.invoke(null, '\r'); // CR
        assertTrue(result);
    }

    @Test
    void testIsLineBreak_withOtherChar() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);
        boolean result = (boolean) method.invoke(null, 'a');
        assertFalse(result);
    }

    @Test
    void testIsLineBreak_withSpace() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);
        boolean result = (boolean) method.invoke(null, ' ');
        assertFalse(result);
    }

    @Test
    void testIsLineBreak_withTab() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);
        boolean result = (boolean) method.invoke(null, '\t');
        assertFalse(result);
    }
}
